}};

function momSetCap(cap, color) {{
  _pendingCap = cap;

  // Update button styles immediately
  var colors = {{High:'#27ae60', Medium:'#e67e22', Low:'#e74c3c'}};
  ['High','Medium','Low'].forEach(function(c) {{
