  var actions = document.getElementById('mom-cap-actions');
  if (!popup) return;

  popup.style.display   = 'block';
  loading.style.display = 'block';
  text.style.display    = 'none';
  text.innerHTML        = '';
  actions.style.display = 'none';

  if (_momHasAI) {{
    fetch('/ai-capacity-preview', {{
      method: 'POST',
